 1: `include "constants.vams"
 2: `include "disciplines.vams"
 3: 
 4: module bandgap_startup_trim(in, clk, rst, out, metric);
 5:   input in, clk, rst;
 6:   output out, metric;
 7:   electrical in, clk, rst, out, metric;
 8:   parameter real vth = 0.5;
 9:   parameter real gain = 0.85;
10:   parameter real bias = 0.0;
11:   real state;
12:   integer count;
13: 
14:   analog begin
15:     @(initial_step) begin
16:       state = 0.0;
17:       count = 0;
18:     end
19:     @(cross(V(rst) - vth, +1)) begin
20:       state = 0.0;
21:       count = 0;
22:     end
23:     @(cross(V(clk) - vth, +1)) begin
24:       state = gain * state + V(in) + bias;
25:       if (state > 1.0) state = 1.0;
26:       if (state < -1.0) state = -1.0;
27:       count = count + 1;
28:     end
29:     V(out) <+ transition(state, 0, 1n);
30:     V(metric) <+ transition(count > 0 ? state / count : 0.0, 0, 1n);
31:   end
32: endmodule

